import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length and truncate if necessary
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length. Truncating...");
            name = name.substring(0, 10);
        }

        // No buffer overflow risk due to fixed buffer size
        char[] buffer = new char[10];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
